// Convenience lookup — flat map of topic-id → { topic, levelId, levelName }.
export const TOPIC_INDEX = (() => {
  const idx = {};
  LEVELS.forEach(level => {
    level.topics.forEach(topic => {
      idx[topic.id] = { topic, levelId: level.id, levelName: level.name };
    });
  });
  return idx;
})();
